#!/bin/bash
# MongoDB Schema Validation Setup
set -euo pipefail

DB="mydb"

echo "=== Creating validated collection ==="
mongosh --quiet --eval "
db.createCollection('products', {
  validator: {
    $jsonSchema: {
      bsonType: 'object',
      required: ['name', 'price', 'category', 'sku'],
      properties: {
        name: {bsonType: 'string', minLength: 1, maxLength: 200},
        price: {bsonType: 'number', minimum: 0},
        category: {enum: ['electronics', 'clothing', 'food', 'books', 'other']},
        sku: {bsonType: 'string', pattern: '^[A-Z]{2,4}-[0-9]{4,8}$'},
        description: {bsonType: 'string', maxLength: 2000},
        tags: {bsonType: 'array', items: {bsonType: 'string'}},
        inStock: {bsonType: 'bool'}
      }
    }
  },
  validationLevel: 'strict',
  validationAction: 'error'
});
print('Collection created with validation');
" "$DB"

echo ""
echo "=== Testing valid insert ==="
mongosh --quiet --eval "
const result = db.products.insertOne({
  name: 'Wireless Mouse',
  price: 29.99,
  category: 'electronics',
  sku: 'ELEC-00142',
  tags: ['wireless', 'mouse', 'usb'],
  inStock: true
});
print('Inserted: ' + result.insertedId);
" "$DB"

echo ""
echo "=== Testing invalid inserts ==="
mongosh --quiet --eval "
const tests = [
  {doc: {name: 'Bad Price', price: -5, category: 'electronics', sku: 'ELEC-0001'}, reason: 'negative price'},
  {doc: {name: 'Bad Category', price: 10, category: 'invalid', sku: 'XX-0001'}, reason: 'invalid enum'},
  {doc: {price: 10, category: 'books', sku: 'BOOK-0001'}, reason: 'missing name'},
  {doc: {name: 'Bad SKU', price: 10, category: 'books', sku: 'bad-sku'}, reason: 'invalid SKU pattern'}
];
tests.forEach(t => {
  try {
    db.products.insertOne(t.doc);
    print('UNEXPECTED: ' + t.reason + ' - should have failed');
  } catch(e) {
    print('BLOCKED (' + t.reason + '): validation correctly rejected');
  }
});
" "$DB"

echo ""
echo "=== Current validation rules ==="
mongosh --quiet --eval "
const info = db.getCollectionInfos({name: 'products'})[0];
printjson(info.options);
" "$DB"
